from torch.utils.data import DataLoader
from torchvision import datasets, models, transforms
from torchvision.models import get_model, get_model_weights


def download_checkpoint(url, dst_path):
    import urllib.request

    with urllib.request.urlopen(url) as response, open(dst_path, "wb") as out_file:
        out_file.write(response.read())
    return dst_path


def load_checkpoint_from_url(url, map_location="cpu"):
    with tempfile.NamedTemporaryFile(suffix=".pt", delete=False) as tmp:
        tmp_path = tmp.name
    try:
        download_checkpoint(url, tmp_path)
        checkpoint = torch.load(tmp_path, map_location=map_location)
    finally:
        try:
            os.remove(tmp_path)
        except OSError:
            pass
    return checkpoint


def resolve_model(model_name, pretrained=True):
    try:
        if pretrained:
            weights_enum = get_model_weights(model_name)
            weights = weights_enum.DEFAULT if weights_enum is not None else None
            if weights is not None:
                return get_model(model_name, weights=weights)
        return get_model(model_name, weights=None)
    except Exception:
        if model_name == "resnet18":
            return models.resnet18(weights=models.ResNet18_Weights.DEFAULT if pretrained else None)
        if model_name == "resnet50":
            return models.resnet50(weights=models.ResNet50_Weights.DEFAULT if pretrained else None)
        if model_name == "mobilenet_v2":
            return models.mobilenet_v2(weights=models.MobileNet_V2_Weights.DEFAULT if pretrained else None)
        raise


def replace_classifier(model, num_classes):
    if hasattr(model, "fc") and isinstance(model.fc, nn.Module):
        in_features = model.fc.in_features
        model.fc = nn.Linear(in_features, num_classes)
        return model
    if hasattr(model, "classifier"):
        classifier = model.classifier
        if isinstance(classifier, nn.Sequential):
            last_linear_idx = None
            for idx in reversed(range(len(classifier))):
                if isinstance(classifier[idx], nn.Linear):
                    last_linear_idx = idx
                    break
            if last_linear_idx is not None:
                in_features = classifier[last_linear_idx].in_features
                classifier[last_linear_idx] = nn.Linear(in_features, num_classes)
                model.classifier = classifier
                return model
        if isinstance(classifier, nn.Linear):
            in_features = classifier.in_features
            model.classifier = nn.Linear(in_features, num_classes)
            return model
    raise ValueError("Unsupported model architecture for classifier replacement.")


def freeze_backbone(model):
    for param in model.parameters():
        param.requires_grad = False
    if hasattr(model, "fc") and isinstance(model.fc, nn.Module):
        for param in model.fc.parameters():
            param.requires_grad = True
    if hasattr(model, "classifier"):
        classifier = model.classifier
        if isinstance(classifier, nn.Module):
            for param in classifier.parameters():
                param.requires_grad = True


def build_dataloaders(data_dir, image_size=224, batch_size=32, num_workers=4):
    train_dir = Path(data_dir) / "train"
    val_dir = Path(data_dir) / "val"

    train_tfms = transforms.Compose(
        [
            transforms.RandomResizedCrop(image_size),
            transforms.RandomHorizontalFlip(),
            transforms.ToTensor(),
            transforms.Normalize([0.485, 0.456, 0.406], [0.229, 0.224, 0.225]),
        ]
    )
    val_tfms = transforms.Compose(
        [
            transforms.Resize(int(image_size * 1.14)),
            transforms.CenterCrop(image_size),
            transforms.ToTensor(),
            transforms.Normalize([0.485, 0.456, 0.406], [0.229, 0.224, 0.225]),
        ]
    )

    train_ds = datasets.ImageFolder(train_dir, transform=train_tfms)
    val_ds = datasets.ImageFolder(val_dir, transform=val_tfms)

    train_loader = DataLoader(train_ds, batch_size=batch_size, shuffle=True, num_workers=num_workers, pin_memory=True)
    val_loader = DataLoader(val_ds, batch_size=batch_size, shuffle=False, num_workers=num_workers, pin_memory=True)
    return train_loader, val_loader, train_ds.classes


def train_one_epoch(model, loader, criterion, optimizer, device):
    model.train()
    running_loss = 0.0
    running_correct = 0
    total = 0

    for inputs, targets in loader:
        inputs = inputs.to(device)
        targets = targets.to(device)

        optimizer.zero_grad(set_to_none=True)
        outputs = model(inputs)
        loss = criterion(outputs, targets)
        loss.backward()
        optimizer.step()

        running_loss += loss.item() * inputs.size(0)
        preds = outputs.argmax(dim=1)
        running_correct += (preds == targets).sum().item()
        total += inputs.size(0)

    return running_loss / max(total, 1), running_correct / max(total, 1)


@torch.no_grad()
def evaluate(model, loader, criterion, device):
    model.eval()
    running_loss = 0.0
    running_correct = 0
    total = 0

    for inputs, targets in loader:
        inputs = inputs.to(device)
        targets = targets.to(device)

        outputs = model(inputs)
        loss = criterion(outputs, targets)

        running_loss += loss.item() * inputs.size(0)
        preds = outputs.argmax(dim=1)
        running_correct += (preds == targets).sum().item()
        total += inputs.size(0)

    return running_loss / max(total, 1), running_correct / max(total, 1)


def save_checkpoint(model, optimizer, epoch, best_acc, path, class_to_idx=None):
    payload = {
        "epoch": epoch,
        "model_state_dict": model.state_dict(),
        "optimizer_state_dict": optimizer.state_dict(),
        "best_acc": best_acc,
    }
    if class_to_idx is not None:
        payload["class_to_idx"] = class_to_idx
    torch.save(payload, path)


def maybe_load_pretrained_checkpoint(model, checkpoint_url, device):
    if not checkpoint_url:
        return model
    checkpoint = load_checkpoint_from_url(checkpoint_url, map_location=device)
    if isinstance(checkpoint, dict):
        state_dict = checkpoint.get("state_dict") or checkpoint.get("model_state_dict") or checkpoint
        if isinstance(state_dict, dict):
            try:
                model.load_state_dict(state_dict, strict=False)
            except Exception:
                pass
    return model


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data-dir", required=True)
    parser.add_argument("--model-name", default="resnet18")
    parser.add_argument("--checkpoint-url", default="")
    parser.add_argument("--epochs", type=int, default=10)
    parser.add_argument("--batch-size", type=int, default=32)
    parser.add_argument("--lr", type=float, default=1e-3)
    parser.add_argument("--image-size", type=int, default=224)
    parser.add_argument("--num-workers", type=int, default=4)
    parser.add_argument("--freeze-backbone", action="store_true")
    parser.add_argument("--output-dir", default="outputs")
    args = parser.parse_args()

    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    os.makedirs(args.output_dir, exist_ok=True)

    train_loader, val_loader, classes = build_dataloaders(
        args.data_dir,
        image_size=args.image_size,
        batch_size=args.batch_size,
        num_workers=args.num_workers,
    )

    model = resolve_model(args.model_name, pretrained=True)
    model = maybe_load_pretrained_checkpoint(model, args.checkpoint_url, device)
    model = replace_classifier(model, num_classes=len(classes))

    if args.freeze_backbone:
        freeze_backbone(model)

    model = model.to(device)

    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam((p for p in model.parameters() if p.requires_grad), lr=args.lr)

    best_acc = 0.0
    best_path = os.path.join(args.output_dir, "best_model.pt")

    for epoch in range(1, args.epochs + 1):
        train_loss, train_acc = train_one_epoch(model, train_loader, criterion, optimizer, device)
        val_loss, val_acc = evaluate(model, val_loader, criterion, device)

        if val_acc > best_acc:
            best_acc = val_acc
            save_checkpoint(model, optimizer, epoch, best_acc, best_path, class_to_idx=train_loader.dataset.class_to_idx)

        print(
            f"epoch={epoch} "
            f"train_loss={train_loss:.4f} train_acc={train_acc:.4f} "
            f"val_loss={val_loss:.4f} val_acc={val_acc:.4f} best_acc={best_acc:.4f}"
        )

    final_path = os.path.join(args.output_dir, "final_model.pt")
    save_checkpoint(model, optimizer, args.epochs, best_acc, final_path, class_to_idx=train_loader.dataset.class_to_idx)


